/**
 * Custom error class for OAuth-related errors
 */
class OAuthError extends Error {
  constructor(code, message, uri = null, httpStatus = null) {
    super(message);
    this.name = 'OAuthError';
    this.code = code;
    this.uri = uri;
    this.httpStatus = httpStatus;
  }

  toJSON() {
    return {
      name: this.name,
      code: this.code,
      message: this.message,
      uri: this.uri,
      httpStatus: this.httpStatus,
    };
  }
}

// ============================================================
// Usage Example
// ============================================================

// Initialize the OAuth client
const oauthClient = new OAuthImplicitClient({
  clientId: 'your-client-id',
  authorizationEndpoint: 'https://auth.example.com/oauth/authorize',
  redirectUri: window.location.origin + '/callback',
  scope: 'read write profile',
  apiBaseUrl: 'https://api.example.com',
});

// Listen for OAuth events
window.addEventListener('oauth:authenticated', (event) => {
  console.log('User authenticated!', event.detail);
  loadUserDashboard();
});

window.addEventListener('oauth:expired', () => {
  console.log('Token expired, attempting silent refresh...');
  oauthClient.silentRefresh().catch(() => {
    showLoginPrompt();
  });
});

window.addEventListener('oauth:expiring_soon', (event) => {
  console.log(`Token expiring in ${event.detail.expiresIn} seconds`);
  oauthClient.silentRefresh().catch(() => {
    console.warn('Silent refresh failed');
  });
});

window.addEventListener('oauth:unauthorized', () => {
  console.log('Unauthorized, redirecting to login...');
  showLoginPrompt();
});

window.addEventListener('oauth:error', (event) => {
  console.error('OAuth Error:', event.detail);
  showErrorMessage(event.detail.message);
});

window.addEventListener('oauth:logout', () => {
  console.log('User logged out');
  showLoginPrompt();
});

// Application functions
function showLoginPrompt() {
  document.getElementById('app').innerHTML = `
    <div class="login-container">
      <h1>Welcome to Our App</h1>
      <p>Please log in to continue.</p>
      <button id="login-btn" class="btn-primary">Log In with OAuth</button>
    </div>
  `;
  document.getElementById('login-btn').addEventListener('click', () => {
    oauthClient.authorize();
  });
}

function showErrorMessage(message) {
  const errorDiv = document.createElement('div');
  errorDiv.className = 'error-notification';
  errorDiv.textContent = `Error: ${message}`;
  document.body.appendChild(errorDiv);
  setTimeout(() => errorDiv.remove(), 5000);
}

async function loadUserDashboard() {
  try {
    // Example API calls using the OAuth client
    const userResponse = await oauthClient.get('/user/profile');
    const userData = await userResponse.json();

    const expiresIn = oauthClient.getTokenExpiresIn();

    document.getElementById('app').innerHTML = `
      <div class="dashboard">
        <header>
          <h1>Welcome, ${userData.name || 'User'}!</h1>
          <span class="token-info">Token expires in: ${expiresIn ? expiresIn + 's' : 'N/A'}</span>
          <button id="logout-btn">Logout</button>
        </header>
        <main>
          <div id="content">Loading...</div>
        </main>
      </div>
    `;

    document.getElementById('logout-btn').addEventListener('click', () => {
      oauthClient.logout();
    });

    // Load additional data
    const dataResponse = await oauthClient.get('/user/data');
    const data = await dataResponse.json();
    document.getElementById('content').innerHTML = `
      <pre>${JSON.stringify(data, null, 2)}</pre>
    `;
  } catch (error) {
    if (error instanceof OAuthError) {
      console.error('OAuth API Error:', error.toJSON());
      if (error.code === 'no_token' || error.code === 'unauthorized') {
        showLoginPrompt();
      }
    } else {
      console.error('Unexpected error:', error);
      showErrorMessage('An unexpected error occurred');
    }
  }
}

// Initialize the application
function initApp() {
  if (oauthClient.isAuthenticated()) {
    loadUserDashboard();
  } else {
    showLoginPrompt();
  }
}

// Start when DOM is ready
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', initApp);
} else {
  initApp();
}

// Export for module usage
if (typeof module !== 'undefined' && module.exports) {
  module.exports = { OAuthImplicitClient, OAuthError };
}